mapper.select:

LEFT JOIN  scm_purchasing_plan c on a.purchasing_plan_id = c.id
LEFT JOIN  wms_replenishment_application d on a.replenishment_id = d.id
left JOIN sys_user f ON a.applicant_id = f.user_id
left JOIN sys_user g ON a.approved_id = g.user_id

     and a.application_no = #{applicationNo}
     and a.application_type = #{applicationType}
     and a.applicant_id = #{applicantId}
     and a.applicant_date between #{params.beginApplicantDate} and #{params.endApplicantDate}
     and a.applicant_status = #{applicantStatus}
     and a.approved_id = #{approvedId}
     and a.approved_date between #{params.beginApprovedDate} and #{params.endApprovedDate}
     and a.approved_status = #{approvedStatus}
     and a.approved_comments = #{approvedComments}
     and c.document_number like concat('%', #{documentNumber}, '%')

mapper.update:
update scm_purchasing_appliction
application_no = #{applicationNo}, application_type = #{applicationType}, purchasing_plan_id = #{purchasingPlanId}, replenishment_id = #{replenishmentId}, applicant_id = #{applicantId}, applicant_date = #{applicantDate}, applicant_status = #{applicantStatus}, approved_id = #{approvedId}, approved_date = #{approvedDate}, approved_status = #{approvedStatus}, approved_comments = #{approvedComments}, remark = #{remark},
where id = #{id}
